const o="/src/offscreen/offscreen.html";async function t(r){await chrome.offscreen.hasDocument()||await chrome.offscreen.createDocument({url:r,reasons:["WORKERS"],justification:"Run Wllama WebAssembly which requires DOM and Web Worker access"})}chrome.runtime.onMessage.addListener((r,s,c)=>{r.action==="PROCESS_TEXT"&&(async()=>{try{await t(o),console.log("📨 Sending text to offscreen document for processing..."),await new Promise(n=>setTimeout(n,500));const e=await chrome.runtime.sendMessage({target:"offscreen",action:"PROCESS_TEXT",text:r.text});if(e&&e.success)chrome.runtime.sendMessage({action:"AI_RESULT",result:e.result});else throw new Error(e?e.error:"Unknown offscreen error")}catch(e){console.error("❌ AI Relay Error Details:",e),chrome.runtime.sendMessage({action:"AI_RESULT",result:"AI Error: "+e.message})}})()});
